package com.travelassistant.consultation.ai;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.stereotype.Component;import java.util.function.Consumer;
@Component @ConditionalOnProperty(name="app.consultation.provider",havingValue="stub",matchIfMissing=true)public class StubConsultationProvider implements ConsultationProvider{public ConsultationResult answer(ConsultationPrompt p){String question=p.messages().getLast().content();String answer="关于“"+question+"”的建议：请结合预算与行程合理安排，并从官方渠道核验实时价格、天气、营业时间、交通及签证政策。";return new ConsultationResult(answer,"stub-consultation-v1",p.messages().size()*10,answer.length());}public ConsultationResult stream(ConsultationPrompt p,Consumer<String> chunks,CancellationToken token){ConsultationResult result=answer(p);for(int i=0;i<result.content().length()&&!token.isCancelled();i+=12)chunks.accept(result.content().substring(i,Math.min(result.content().length(),i+12)));if(token.isCancelled())throw new IllegalStateException("cancelled");return result;}public String providerName(){return"stub";}public String modelName(){return"stub-consultation-v1";}}
